import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import './Courses.css';

const Courses = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState('all');
  const { user } = useAuth();

  const courseCategories = [
    'all', 'technology', 'business', 'design', 'data-science', 
    'marketing', 'healthcare', 'finance', 'engineering', 
    'creative-arts', 'education', 'personal-development'
  ];

  useEffect(() => {
    fetchCourses();
  }, []);

  const fetchCourses = async () => {
    setLoading(true);
    try {
      const comprehensiveCourses = [
        // Technology Courses
        {
          id: 1, title: 'Complete Web Development Bootcamp', platform: 'Udemy', category: 'technology',
          duration: '40h', level: 'All Levels', rating: 4.7, students: '1.5M', price: '$89.99',
          image: 'https://img-c.udemycdn.com/course/240x135/1565838_e54e_16.jpg',
          link: 'https://www.udemy.com/course/the-complete-web-development-bootcamp/',
          skills: ['HTML', 'CSS', 'JavaScript', 'React', 'Node.js']
        },
        {
          id: 2, title: 'Python for Everybody', platform: 'Coursera', category: 'technology',
          duration: '3mo', level: 'Beginner', rating: 4.8, students: '1.2M', price: 'Free',
          image: 'https://img-c.udemycdn.com/course/240x135/903744_8eb2.jpg',
          link: 'https://www.coursera.org/specializations/python',
          skills: ['Python', 'Programming', 'Data Structures']
        },
        {
          id: 3, title: 'AWS Cloud Practitioner', platform: 'AWS', category: 'technology',
          duration: '6h', level: 'Beginner', rating: 4.6, students: '800K', price: 'Free',
          image: 'https://img-c.udemycdn.com/course/240x135/3148696_4e81_3.jpg',
          link: 'https://www.aws.training/Details/eLearning?id=32143',
          skills: ['AWS', 'Cloud Computing', 'Security']
        },

        // Data Science Courses
        {
          id: 4, title: 'Machine Learning Specialization', platform: 'Coursera', category: 'data-science',
          duration: '3mo', level: 'Intermediate', rating: 4.8, students: '500K', price: 'Free',
          image: 'https://img-c.udemycdn.com/course/240x135/950390_270f_3.jpg',
          link: 'https://www.coursera.org/specializations/machine-learning-introduction',
          skills: ['Python', 'ML', 'TensorFlow', 'Data Analysis']
        },
        {
          id: 5, title: 'Data Science Certificate', platform: 'edX', category: 'data-science',
          duration: '9mo', level: 'Intermediate', rating: 4.5, students: '300K', price: '$356',
          image: 'https://img-c.udemycdn.com/course/240x135/1754098_e0df_3.jpg',
          link: 'https://www.edx.org/professional-certificate/harvardx-data-science',
          skills: ['R', 'Statistics', 'Data Visualization']
        },

        // Business Courses
        {
          id: 6, title: 'Business Foundations', platform: 'Coursera', category: 'business',
          duration: '6mo', level: 'Beginner', rating: 4.7, students: '400K', price: 'Free',
          image: 'https://img-c.udemycdn.com/course/240x135/3510304_8f5c_3.jpg',
          link: 'https://www.coursera.org/specializations/wharton-business-foundations',
          skills: ['Marketing', 'Accounting', 'Strategy']
        },
        {
          id: 7, title: 'Project Management', platform: 'Google', category: 'business',
          duration: '6mo', level: 'Beginner', rating: 4.6, students: '600K', price: '$39/mo',
          image: 'https://img-c.udemycdn.com/course/240x135/3968766_5d3a_4.jpg',
          link: 'https://grow.google/certificates/project-management/',
          skills: ['Planning', 'Risk Management']
        },

        // Design Courses
        {
          id: 8, title: 'UI/UX Design', platform: 'Coursera', category: 'design',
          duration: '6mo', level: 'Beginner', rating: 4.6, students: '300K', price: 'Free',
          image: 'https://img-c.udemycdn.com/course/240x135/1650610_6654_3.jpg',
          link: 'https://www.coursera.org/specializations/ui-ux-design',
          skills: ['Figma', 'User Research', 'Prototyping']
        },
        {
          id: 9, title: 'Graphic Design Masterclass', platform: 'Udemy', category: 'design',
          duration: '15h', level: 'All Levels', rating: 4.7, students: '250K', price: '$84.99',
          image: 'https://img-c.udemycdn.com/course/240x135/1643044_299d_5.jpg',
          link: 'https://www.udemy.com/course/graphic-design-masterclass/',
          skills: ['Photoshop', 'Illustrator', 'Typography']
        },

        // Marketing Courses
        {
          id: 10, title: 'Digital Marketing', platform: 'Google', category: 'marketing',
          duration: '40h', level: 'Beginner', rating: 4.5, students: '800K', price: 'Free',
          image: 'https://img-c.udemycdn.com/course/240x135/914296_3670_8.jpg',
