        },

        // Healthcare Courses
        {
          id: 11, title: 'Public Health', platform: 'Coursera', category: 'healthcare',
          duration: '15h', level: 'Beginner', rating: 4.7, students: '150K', price: 'Free',
          image: 'https://img-c.udemycdn.com/course/240x135/2480346_3023_3.jpg',
          link: 'https://www.coursera.org/learn/public-health',
          skills: ['Epidemiology', 'Health Policy']
        },

        // Finance Courses
        {
          id: 12, title: 'Financial Markets', platform: 'Coursera', category: 'finance',
          duration: '33h', level: 'Beginner', rating: 4.8, students: '400K', price: 'Free',
          image: 'https://img-c.udemycdn.com/course/240x135/1754002_6c0d_2.jpg',
          link: 'https://www.coursera.org/learn/financial-markets-global',
          skills: ['Investment', 'Risk Management']
        },

        // Engineering Courses
        {
          id: 13, title: 'Mechanical Engineering', platform: 'Udemy', category: 'engineering',
          duration: '9h', level: 'Beginner', rating: 4.4, students: '120K', price: '$84.99',
          image: 'https://img-c.udemycdn.com/course/240x135/3147464_8f3e_4.jpg',
          link: 'https://www.udemy.com/course/mechanical-engineering-and-electrical-engineering-explained/',
          skills: ['Systems', 'Circuits', 'Principles']
        },

        // Creative Arts Courses
        {
          id: 14, title: 'Music Production', platform: 'Coursera', category: 'creative-arts',
          duration: '6mo', level: 'Beginner', rating: 4.7, students: '150K', price: 'Free',
          image: 'https://img-c.udemycdn.com/course/240x135/1327382_6a16_5.jpg',
          link: 'https://www.coursera.org/specializations/music-production',
          skills: ['Audio', 'Mixing', 'Mastering']
        },

        // Education Courses
        {
          id: 15, title: 'Learning How to Learn', platform: 'Coursera', category: 'education',
          duration: '15h', level: 'Beginner', rating: 4.8, students: '3M', price: 'Free',
          image: 'https://img-c.udemycdn.com/course/240x135/1362070_b8a1_2.jpg',
          link: 'https://www.coursera.org/learn/learning-how-to-learn',
          skills: ['Study Techniques', 'Memory']
        },

        // Personal Development Courses
        {
          id: 16, title: 'Science of Well-Being', platform: 'Coursera', category: 'personal-development',
          duration: '19h', level: 'Beginner', rating: 4.9, students: '3.5M', price: 'Free',
          image: 'https://img-c.udemycdn.com/course/240x135/1906852_0c6e_5.jpg',
          link: 'https://www.coursera.org/learn/the-science-of-well-being',
          skills: ['Happiness', 'Mindfulness']
        }
      ];
      
      setCourses(comprehensiveCourses);
    } catch (error) {
      console.error('Error fetching courses:', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredCourses = selectedCategory === 'all' 
    ? courses 
    : courses.filter(course => course.category === selectedCategory);

  const enrollCourse = (courseLink) => {
    window.open(courseLink, '_blank');
  };

  const getCategoryIcon = (category) => {
    const icons = {
      'technology': '💻', 'business': '💼', 'design': '🎨', 'data-science': '📊',
      'marketing': '📱', 'healthcare': '🏥', 'finance': '💰', 'engineering': '⚙️',
      'creative-arts': '🎭', 'education': '📚', 'personal-development': '🌟', 'all': '📚'
    };
    return icons[category] || '📚';
  };

  if (!user) {
    return (
      <div className="courses-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to explore courses.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="courses-container">
        <div className="container">
          <div className="loading">
            <div className="spinner"></div>
            <p>Loading course catalog...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="courses-container">
      <div className="container">
        {/* Compact Header */}
        <div className="courses-header">
          <h1>📚 Course Catalog</h1>
          <p>Explore courses across all domains</p>
        </div>

        {/* Compact Filters */}
        <div className="courses-filters">
          <div className="filter-buttons">
            {courseCategories.map(category => (
              <button
                key={category}
                className={`filter-btn ${selectedCategory === category ? 'active' : ''}`}
                onClick={() => setSelectedCategory(category)}
                title={category.replace('-', ' ')}
              >
                {getCategoryIcon(category)}
                <span className="btn-text">
                  {category === 'all' ? 'All' : category.charAt(0).toUpperCase() + category.slice(1).replace('-', ' ').substring(0, 8)}
                </span>
              </button>
            ))}
          </div>
        </div>

        {/* Course Counter */}
        <div className="courses-counter">
          <span>{filteredCourses.length} courses in {selectedCategory === 'all' ? 'All Domains' : selectedCategory.replace('-', ' ')}</span>
        </div>

        {/* Compact Grid */}
        <div className="courses-grid compact-grid">
          {filteredCourses.map(course => (
            <div key={course.id} className="course-card compact-card">
              <div className="course-image">
                <img src={course.image} alt={course.title} />
                <span className="platform-badge">{course.platform}</span>
              </div>
              
              <div className="course-content">
                <h3 title={course.title}>{course.title}</h3>
                
                <div className="course-meta">
                  <span className="rating">⭐ {course.rating}</span>
                  <span className="duration">{course.duration}</span>
                  <span className="level">{course.level}</span>
                </div>

                <div className="course-skills">
                  <div className="skills-tags">
                    {course.skills.slice(0, 3).map((skill, index) => (
                      <span key={index} className="skill-tag">{skill}</span>
                    ))}
                    {course.skills.length > 3 && (
                      <span className="skill-tag more">+{course.skills.length - 3}</span>
                    )}
                  </div>
                </div>

                <div className="course-footer">
                  <div className="course-pricing">
                    <span className="price">{course.price}</span>
                  </div>
                  <button 
                    onClick={() => enrollCourse(course.link)}
                    className="btn enroll-btn"
                    title={`Enroll on ${course.platform}`}
                  >
                    Enroll
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

        {filteredCourses.length === 0 && (
          <div className="no-courses">
            <h3>No courses found</h3>
            <p>Try selecting a different category</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Courses;
